const bcvItem = $('Fetch Oficial').item.json;
const parItem = $('Fetch Paralelo').item.json;

const bcv = parseFloat(bcvItem.promedio || bcvItem.price);
const par = parseFloat(parItem.promedio || parItem.price);
const apiDateStr = bcvItem.fechaActualizacion;

const now = new Date();
let targetDate = new Date();

if (apiDateStr) {
  const apiDate = new Date(apiDateStr);
  if (Math.abs(now - apiDate) / (1000 * 60 * 60 * 24) <= 5) {
      targetDate = apiDate;
  }
} else {
  if (now.getHours() >= 17) {
    targetDate.setDate(targetDate.getDate() + 1);
  }
}

const targetDateStr = targetDate.toISOString().split('T')[0];
const bcv_4d = Number(bcv.toFixed(4));
const difcamb = Number((par / bcv_4d).toFixed(6));

const sql = `
  DECLARE @targetDate DATE = '${targetDateStr}';
  DECLARE @bcv FLOAT = ${bcv_4d};
  DECLARE @paralelo FLOAT = ${par};
  DECLARE @difcamb FLOAT = ${difcamb};

  UPDATE SACONF SET Factor = @bcv, FactorM = @bcv;

  IF EXISTS (SELECT 1 FROM dolartoday WHERE CAST(fecha AS DATE) = @targetDate)
  BEGIN
      UPDATE dolartoday
      SET Dolartoday = @paralelo, pendiente = 0, DifCamb = ROUND(@paralelo / NULLIF(dolarbcv, 0), 6), _hora = dbo.sfAA_HoraClarion(GETDATE())
      WHERE id = (SELECT TOP 1 id FROM dolartoday WHERE CAST(fecha AS DATE) = @targetDate ORDER BY id DESC);
  END
  ELSE
  BEGIN
      INSERT INTO dolartoday (fecha, _fecha, _hora, Dolartoday, dolarbcv, pendiente, DifCamb, fuente)
      VALUES (@targetDate, dbo.sfAA_FechaClarion(@targetDate), dbo.sfAA_HoraClarion(GETDATE()), @paralelo, @bcv, 0, @difcamb, 'api');
  END
`;

return [{ json: { sql_query: sql, bcv: bcv_4d, paralelo: par, targetDate: targetDateStr } }];
